import React, { useState, useEffect, useRef } from 'react';
import SidebarLeft from './components/SidebarLeft';
import SidebarRight from './components/SidebarRight';
import HeroSection from './components/HeroSection';
import AboutSection from './components/AboutSection';
import ResumeSection from './components/ResumeSection';
import ServicesSection from './components/ServicesSection';
import SkillsSection from './components/SkillsSection';
import PortfolioSection from './components/PortfolioSection';
import TestimonialSection from './components/TestimonialSection';
import ContactSection from './components/ContactSection';
import Footer from './components/Footer';
import { NAV_ITEMS } from './constants';
import { X, Menu as MenuIcon } from 'lucide-react';

// Use window references for GSAP since we use script tags
declare const gsap: any;
declare const ScrollTrigger: any;

const App: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const mainRef = useRef<HTMLElement>(null);

  useEffect(() => {
    // Wait for components to mount
    if (typeof gsap !== 'undefined' && typeof ScrollTrigger !== 'undefined') {
      gsap.registerPlugin(ScrollTrigger);

      const sections = ['#home', '#about', '#resume', '#services', '#skills', '#portfolio', '#testimonial', '#contact'];

      sections.forEach((id) => {
        const element = document.querySelector(id);
        if (element) {
          gsap.fromTo(element, 
            { 
              opacity: 0, 
              y: 50 
            },
            { 
              opacity: 1, 
              y: 0,
              duration: 1.2,
              ease: "expo.out",
              scrollTrigger: {
                trigger: element,
                start: "top 85%", 
                // Using standard window scroll for mobile compatibility
                // but checking if we are in the desktop scrollable container
                scroller: window.innerWidth >= 1024 ? mainRef.current : window,
                toggleActions: "play none none none"
              }
            }
          );
        }
      });
    }

    return () => {
      if (typeof ScrollTrigger !== 'undefined') {
        ScrollTrigger.getAll().forEach((t: any) => t.kill());
      }
    };
  }, []);

