import { gsap as gsapModule } from 'gsap';
import { ScrollTrigger as ScrollTriggerModule } from 'gsap/ScrollTrigger';

const App: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const mainRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const activeGsap = (window as any).gsap || gsapModule;
    const activeScrollTrigger = (window as any).ScrollTrigger || ScrollTriggerModule;

    if (activeGsap && activeScrollTrigger) {
      activeGsap.registerPlugin(activeScrollTrigger);
      const animElements = document.querySelectorAll('[data-gsap-animate]');

      animElements.forEach((el) => {
        const animation = el.getAttribute('data-gsap-animate') || 'fade-up';
        const delay = parseFloat(el.getAttribute('data-gsap-delay') || '0');
        const scroller = window.innerWidth >= 1024 ? mainRef.current : window;

        let fromVars: any = { opacity: 0 };
        let toVars: any = { 
          opacity: 1, 
          duration: 1, 
          delay: delay,
          ease: "power3.out",
          scrollTrigger: {
            trigger: el,
            start: "top 90%",
            scroller: scroller,
            toggleActions: "play none none none"
          }
        };

        switch (animation) {
          case 'fade-up':
            fromVars.y = 40;
            toVars.y = 0;
            break;
          case 'fade-down':
            fromVars.y = -40;
            toVars.y = 0;
            break;
          case 'fade-left':
            fromVars.x = 40;
            toVars.x = 0;
            break;
          case 'fade-right':
            fromVars.x = -40;
            toVars.x = 0;
            break;
          case 'scale-in':
            fromVars.scale = 0.8;
            toVars.scale = 1;
            break;
          case 'spin-in':
            fromVars.rotation = -15;
            fromVars.scale = 0.9;
            toVars.rotation = 0;
            toVars.scale = 1;
            break;
          case 'rotate-y':
             fromVars.rotationY = 45;
             toVars.rotationY = 0;
             break;
        }

        activeGsap.fromTo(el, fromVars, toVars);
      });

      const containers = document.querySelectorAll('[data-gsap-stagger]');
      containers.forEach((container) => {
        const children = container.querySelectorAll(':scope > *');
        const scroller = window.innerWidth >= 1024 ? mainRef.current : window;

        activeGsap.fromTo(children, 
          { opacity: 0, y: 30 },
          { 
            opacity: 1, 
            y: 0, 
            duration: 0.8,
            stagger: 0.15,
            ease: "power2.out",
            scrollTrigger: {
              trigger: container,
              start: "top 85%",
              scroller: scroller,
              toggleActions: "play none none none"
            }
          }
        );
      });
    }

    return () => {
      if (activeScrollTrigger) {
        activeScrollTrigger.getAll().forEach((t: any) => t.kill());
      }
    };
  }, []);

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
      if (window.innerWidth >= 1024 && mainRef.current) {
        mainRef.current.scrollTo({
          top: element.offsetTop,
          behavior: 'smooth'
        });
      } else {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }
    setIsMenuOpen(false);
  };

  return (
    <div className="min-h-screen bg-[#000] text-white relative flex flex-col lg:flex-row overflow-x-hidden selection:bg-[#28e98c] selection:text-black">
      <div className="lg:hidden fixed top-0 left-0 w-full p-6 flex justify-between items-center z-[70] pointer-events-none">
        <div className="flex items-center gap-1 pointer-events-auto bg-black/80 backdrop-blur-md px-4 py-2 rounded-full border border-[#333]">
          <span className="text-xl font-bold tracking-tight">Drake</span>
          <div className="w-3 h-3 rounded-full border border-[#444] flex items-center justify-center">
            <span className="text-[6px] text-[#999] font-bold">D</span>
          </div>
        </div>
        <button 
          onClick={() => setIsMenuOpen(true)}
          className="w-12 h-12 bg-[#333] hover:bg-[#444] border border-[#444] rounded-full flex items-center justify-center text-white pointer-events-auto transition-all active:scale-90"
        >
          <MenuIcon size={20} />
        </button>
      </div>

      <SidebarLeft />

      <main 
        ref={mainRef}
        className="flex-1 lg:ml-[380px] lg:mr-[100px] lg:h-screen lg:overflow-y-auto relative scroll-smooth"
      >
        <div className="max-w-4xl mx-auto px-6 md:px-10 lg:px-6 mt-10 lg:mt-0 pb-10">
          <section id="home">
            <HeroSection />
          </section>

          <section id="about">
            <AboutSection />
          </section>

          <section id="resume">
            <ResumeSection />
          </section>

          <section id="services">
            <ServicesSection />
          </section>

          <section id="skills">
            <SkillsSection />
          </section>

          <section id="portfolio">
            <PortfolioSection />
          </section>

          <section id="testimonial">
            <TestimonialSection />
          </section>

          <section id="contact">
            <ContactSection />
          </section>

          <Footer />
        </div>
      </main>

      <SidebarRight />

      <div 
        className={`fixed inset-0 bg-[#000] z-[100] transition-transform duration-500 ease-in-out flex flex-col items-center justify-center ${
          isMenuOpen ? 'translate-y-0' : '-translate-y-full'
        }`}
      >
        <button 
          onClick={() => setIsMenuOpen(false)}
          className="absolute top-8 right-8 w-14 h-14 bg-[#333] border border-[#444] rounded-full flex items-center justify-center text-white hover:text-[#28e98c]"
        >
          <X size={28} />
        </button>

        <nav className="flex flex-col gap-6 text-center">
          <p className="text-[#666] uppercase tracking-[5px] text-[10px] mb-8">Menu</p>
          {NAV_ITEMS.map((item) => (
            <button 
              key={item.id}
              onClick={() => scrollToSection(item.id)}
              className="text-3xl font-light hover:text-[#28e98c] transition-colors flex items-center justify-center gap-5 group"
            >
              <span className="text-[#666] group-hover:text-[#28e98c] transition-colors">{item.icon}</span>
              {item.label}
            </button>
          ))}
        </nav>
      </div>
    </div>
  );
};

export default App;

