import React, { useEffect, useRef } from 'react';

interface BackgroundControllerProps {
  type: string;
  primaryColor: string;
}

const BackgroundController: React.FC<BackgroundControllerProps> = ({ type, primaryColor }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let time = 0;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize);
    resize();

    const hexToRgb = (hex: string) => {
      const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
      return result ? {
        r: parseInt(result[1], 16),
        g: parseInt(result[2], 16),
        b: parseInt(result[3], 16)
      } : { r: 40, g: 233, b: 140 };
    };

    const rgb = hexToRgb(primaryColor);
    const colorStr = `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.15)`;

    const draw = () => {
      time += 0.01;
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      switch (type) {
        case 'Earth Lines Sphere': {
          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;
          const radius = Math.min(canvas.width, canvas.height) * 0.35;
          ctx.strokeStyle = colorStr;
          ctx.lineWidth = 1;

          for (let i = 0; i < 20; i++) {
            const lat = (i / 20) * Math.PI;
            ctx.beginPath();
            const rLat = radius * Math.sin(lat);
            const zLat = radius * Math.cos(lat);

            // Draw horizontal circles with 3D projection feel
            ctx.ellipse(centerX, centerY + zLat * Math.sin(time * 0.5), rLat, rLat * 0.3, time, 0, Math.PI * 2);
            ctx.stroke();
          }

          for (let i = 0; i < 10; i++) {
            const lon = (i / 10) * Math.PI + time;
            ctx.beginPath();
            ctx.ellipse(centerX, centerY, radius, radius, lon, 0, Math.PI * 2);
            ctx.stroke();
          }
          break;
        }

        case '3D Abstract Ball': {
          const centerX = canvas.width / 2;
          const centerY = canvas.height / 2;
          for (let i = 0; i < 5; i++) {
            const offset = i * (Math.PI / 2.5);
            const x = centerX + Math.cos(time + offset) * 100;
            const y = centerY + Math.sin(time * 0.8 + offset) * 100;
            const r = 50 + Math.sin(time + offset) * 20;

            const grad = ctx.createRadialGradient(x, y, 0, x, y, r);
            grad.addColorStop(0, `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.2)`);
            grad.addColorStop(1, 'transparent');

            ctx.fillStyle = grad;
            ctx.beginPath();
            ctx.arc(x, y, r, 0, Math.PI * 2);
            ctx.fill();
          }
          break;
        }

        case 'Water Waves': {
          ctx.beginPath();
          ctx.strokeStyle = colorStr;
          ctx.lineWidth = 2;
          for (let j = 0; j < 3; j++) {
            ctx.moveTo(0, canvas.height * (0.5 + j * 0.1));
            for (let x = 0; x < canvas.width; x++) {
              const y = Math.sin(x * 0.005 + time + j) * 50 + canvas.height * (0.5 + j * 0.1);
              ctx.lineTo(x, y);
            }
          }
          ctx.stroke();
          break;
        }

        case 'Liquids Wavy': {
          // Plasma/Liquid effect
          const step = 20;
          for (let x = 0; x < canvas.width; x += step) {
            for (let y = 0; y < canvas.height; y += step) {
              const v = Math.sin(x * 0.01 + time) + Math.sin(y * 0.01 + time) + Math.sin((x + y) * 0.01 + time);
              if (v > 2.0) {
                ctx.fillStyle = `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${0.05 * (v - 2.0)})`;
                ctx.fillRect(x, y, step, step);
              }
            }
          }
          break;
        }

        case 'Simple Strings': {
          ctx.strokeStyle = colorStr;
          ctx.lineWidth = 0.5;
          const points = 15;
          for (let i = 0; i < points; i++) {
            const x1 = Math.sin(time * 0.5 + i) * (canvas.width / 2) + (canvas.width / 2);
            const y1 = Math.cos(time * 0.3 + i * 2) * (canvas.height / 2) + (canvas.height / 2);
            const x2 = Math.cos(time * 0.2 + i * 3) * (canvas.width / 2) + (canvas.width / 2);
            const y2 = Math.sin(time * 0.7 + i * 4) * (canvas.height / 2) + (canvas.height / 2);

            ctx.beginPath();
            ctx.moveTo(x1, y1);
            ctx.bezierCurveTo(canvas.width / 2, canvas.height / 2, x1, y2, x2, y2);
            ctx.stroke();
          }
          break;
        }

        default: // Solid Color - basically clear
          break;
      }

      animationFrameId = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, [type, primaryColor]);

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed inset-0 pointer-events-none z-0 opacity-40 transition-opacity duration-1000"
    />
  );
};

export default BackgroundController;

import React, { useState, useEffect, useRef } from 'react';
import SidebarLeft from './components/SidebarLeft';
import SidebarRight from './components/SidebarRight';
import HeroSection from './components/HeroSection';
import AboutSection from './components/AboutSection';
import ResumeSection from './components/ResumeSection';
import ServicesSection from './components/ServicesSection';
import SkillsSection from './components/SkillsSection';
import PortfolioSection from './components/PortfolioSection';
import TestimonialSection from './components/TestimonialSection';
import ContactSection from './components/ContactSection';
import Footer from './components/Footer';
import BackgroundController from './components/BackgroundController';
import { NAV_ITEMS } from './constants';
import { X, Menu as MenuIcon, Instagram, Twitter, Facebook } from 'lucide-react';

import { gsap as gsapModule } from 'gsap';
import { ScrollTrigger as ScrollTriggerModule } from 'gsap/ScrollTrigger';

const THEME_COLORS = [
  { name: 'Mint', value: '#28e98c' },
  { name: 'Yellow', value: '#e4af12' },
  { name: 'Orange', value: '#fe6f1d' },
  { name: 'Cyan', value: '#14c5fd' },
  { name: 'Grey', value: '#c0c0c0' },
  { name: 'Blue', value: '#1338f3' },
  { name: 'Red', value: '#f31313' },
  { name: 'Pink', value: '#ff99cc' },
];

const BACKGROUNDS = [
  'Earth Lines Sphere',
  '3D Abstract Ball',
  'Water Waves',
  'Liquids Wavy',
  'Solid Color',
  'Simple Strings',
];

const App: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isConfigOpen, setIsConfigOpen] = useState(false);
  const [primaryColor, setPrimaryColor] = useState('#28e98c');
  const [bgType, setBgType] = useState('Earth Lines Sphere');
  const mainRef = useRef<HTMLElement>(null);

  useEffect(() => {
    // Update CSS Variable for primary color
    document.documentElement.style.setProperty('--primary', primaryColor);

    // Helper to get RGB from hex for shadow opacity
    const hexToRgb = (hex: string) => {
      const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
      return result ? 
        `${parseInt(result[1], 16)}, ${parseInt(result[2], 16)}, ${parseInt(result[3], 16)}` : 
        '40, 233, 140';
    };
    document.documentElement.style.setProperty('--primary-rgb', hexToRgb(primaryColor));
  }, [primaryColor]);

  useEffect(() => {
    const activeGsap = (window as any).gsap || gsapModule;
    const activeScrollTrigger = (window as any).ScrollTrigger || ScrollTriggerModule;

    if (activeGsap && activeScrollTrigger) {
      activeGsap.registerPlugin(activeScrollTrigger);
      const animElements = document.querySelectorAll('[data-gsap-animate]');

      animElements.forEach((el) => {
        const animation = el.getAttribute('data-gsap-animate') || 'fade-up';
        const delay = parseFloat(el.getAttribute('data-gsap-delay') || '0');
        const scroller = window.innerWidth >= 1024 ? mainRef.current : window;

        let fromVars: any = { opacity: 0 };
        let toVars: any = { 
          opacity: 1, 
          duration: 1, 
          delay: delay,
          ease: "power3.out",
          scrollTrigger: {
            trigger: el,
            start: "top 90%",
            scroller: scroller,
            toggleActions: "play none none none"
          }
        };

        switch (animation) {
          case 'fade-up':
            fromVars.y = 40;
            toVars.y = 0;
            break;
          case 'fade-down':
            fromVars.y = -40;
            toVars.y = 0;
            break;
          case 'fade-left':
            fromVars.x = 40;
            toVars.x = 0;
            break;
          case 'fade-right':
            fromVars.x = -40;
            toVars.x = 0;
            break;
          case 'scale-in':
            fromVars.scale = 0.8;
            toVars.scale = 1;
            break;
          case 'spin-in':
            fromVars.rotation = -15;
            fromVars.scale = 0.9;
            toVars.rotation = 0;
            toVars.scale = 1;
            break;
        }

        activeGsap.fromTo(el, fromVars, toVars);
      });

      const containers = document.querySelectorAll('[data-gsap-stagger]');
      containers.forEach((container) => {
        const children = container.querySelectorAll(':scope > *');
        const scroller = window.innerWidth >= 1024 ? mainRef.current : window;

        activeGsap.fromTo(children, 
          { opacity: 0, y: 30 },
          { 
            opacity: 1, 
            y: 0, 
            duration: 0.8,
            stagger: 0.15,
            ease: "power2.out",
            scrollTrigger: {
              trigger: container,
              start: "top 85%",
              scroller: scroller,
              toggleActions: "play none none none"
            }
          }
        );
      });
    }

    return () => {
      if (activeScrollTrigger) {
        activeScrollTrigger.getAll().forEach((t: any) => t.kill());
      }
    };
  }, []);

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
      if (window.innerWidth >= 1024 && mainRef.current) {
        mainRef.current.scrollTo({
          top: element.offsetTop,
          behavior: 'smooth'
        });
      } else {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }
    setIsMenuOpen(false);
  };

  return (
    <div className="min-h-screen bg-[#000] text-white relative flex flex-col lg:flex-row overflow-x-hidden selection:bg-[var(--primary)] selection:text-black">
